// Audit-log viewer — calls AuditSink.verify_chain() per topic and
// renders the hash-chain integrity status.
// Generated by flowforge JTBD generator — do not edit by hand.
import * as React from "react";

import { adminApi, type AdminAuditChain } from "../api";

const AUDIT_TOPICS: ReadonlyArray<string> = [
	"complete_hire.approved",
	"complete_hire.candidate_withdrawal_rejected",
	"complete_hire.submitted",
	"conduct_interview.approved",
	"conduct_interview.no_show",
	"conduct_interview.submitted",
	"extend_offer.approved",
	"extend_offer.counter_offer",
	"extend_offer.escalated",
	"extend_offer.offer_expired_rejected",
	"extend_offer.submitted",
	"screen_candidate.approved",
	"screen_candidate.salary_above_band",
	"screen_candidate.submitted",
	"source_candidate.approved",
	"source_candidate.duplicate_candidate_rejected",
	"source_candidate.submitted",
];

interface TopicState {
	topic: string;
	chain: AdminAuditChain | null;
	loading: boolean;
	error: string | null;
}

export function AuditLogViewer(): React.ReactElement {
	const initial: ReadonlyArray<TopicState> = AUDIT_TOPICS.map((t) => ({
		topic: t,
		chain: null,
		loading: false,
		error: null,
	}));
	const [topics, setTopics] = React.useState<ReadonlyArray<TopicState>>(initial);
	const [selected, setSelected] = React.useState<string | null>(
		AUDIT_TOPICS.length > 0 ? (AUDIT_TOPICS[0] ?? null) : null,
	);

	const verify = React.useCallback(async (topic: string) => {
		setTopics((prev) =>
			prev.map((t) => (t.topic === topic ? { ...t, loading: true, error: null } : t)),
		);
		try {
			const chain = await adminApi.verifyAuditChain(topic);
			setTopics((prev) =>
				prev.map((t) =>
					t.topic === topic ? { ...t, chain, loading: false, error: null } : t,
				),
			);
		} catch (e: unknown) {
			const msg = e instanceof Error ? e.message : "verify failed";
			setTopics((prev) =>
				prev.map((t) => (t.topic === topic ? { ...t, loading: false, error: msg } : t)),
			);
		}
	}, []);

	const verifyAll = React.useCallback(() => {
		for (const t of AUDIT_TOPICS) {
			void verify(t);
		}
	}, [verify]);

	const current = topics.find((t) => t.topic === selected) ?? null;

	return (
		<section aria-labelledby="audit-heading">
			<h2 id="audit-heading">Audit log</h2>
			<p className="ff-admin-hint">
				Verifies the audit hash-chain by calling <code>AuditSink.verify_chain()</code>{" "}
				on the host (Postgres-backed by <code>flowforge-audit-pg</code>). A red status
				means the chain is broken — investigate immediately.
			</p>
			<div className="ff-admin-toolbar">
				<button type="button" onClick={verifyAll}>
					Verify all topics
				</button>
			</div>
			<div className="ff-admin-split">
				<aside>
					<h3>Topics</h3>
					<ul>
						{topics.map((t) => {
							const status = t.chain?.verified === true
								? "ok"
								: t.chain?.verified === false
									? "broken"
									: t.error
										? "error"
										: "pending";
							return (
								<li key={t.topic}>
									<button
										type="button"
										aria-current={t.topic === selected ? "true" : undefined}
										onClick={() => {
											setSelected(t.topic);
											if (t.chain == null && !t.loading) void verify(t.topic);
										}}
									>
										<span className={`ff-admin-status ff-admin-status-${status}`}>
											{status}
										</span>{" "}
										{t.topic}
									</button>
								</li>
							);
						})}
					</ul>
				</aside>
				<div className="ff-admin-detail">
					{current == null ? (
						<p>Select a topic to verify its hash-chain.</p>
					) : (
						<>
							<h3>{current.topic}</h3>
							{current.loading ? <p>Verifying…</p> : null}
							{current.error ? (
								<p role="alert" className="ff-admin-error">
									{current.error}
								</p>
							) : null}
							{current.chain ? (
								<>
									<p>
										Status:{" "}
										<strong className={current.chain.verified ? "ok" : "broken"}>
											{current.chain.verified ? "intact" : "BROKEN"}
										</strong>
										{current.chain.failure_at ? (
											<>
												{" "}
												(first failure at <code>{current.chain.failure_at}</code>)
											</>
										) : null}
									</p>
									<table className="ff-admin-table">
										<thead>
											<tr>
												<th scope="col">id</th>
												<th scope="col">tenant</th>
												<th scope="col">actor</th>
												<th scope="col">payload hash</th>
												<th scope="col">prev hash</th>
												<th scope="col">created</th>
											</tr>
										</thead>
										<tbody>
											{current.chain.entries.map((e) => (
												<tr key={e.id}>
													<td>
														<code>{e.id}</code>
													</td>
													<td>{e.tenant_id}</td>
													<td>{e.actor}</td>
													<td>
														<code>{e.payload_hash.slice(0, 16)}…</code>
													</td>
													<td>
														<code>{e.prev_hash ? `${e.prev_hash.slice(0, 16)}…` : "—"}</code>
													</td>
													<td>
														<time dateTime={e.created_at}>{e.created_at}</time>
													</td>
												</tr>
											))}
										</tbody>
									</table>
								</>
							) : null}
						</>
					)}
				</div>
			</div>
		</section>
	);
}
